import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  TextField,
  Box,
  Typography,
  Divider,
  Alert,
  CircularProgress,
  IconButton,
  InputAdornment,
  Grid,
  Card,
  CardContent,
  Chip
} from '@mui/material';
import {
  Close,
  Visibility,
  VisibilityOff,
  Person,
  Api,
  Save,
  Check
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import authService from '../../services/authService';

const Profile = ({ open, onClose, user, onUserUpdate }) => {
  const [loading, setLoading] = useState(false);
  const [showApiKey, setShowApiKey] = useState(false);
  const [showSecretKey, setShowSecretKey] = useState(false);
  const [showPassphrase, setShowPassphrase] = useState(false);
  const [formData, setFormData] = useState({
    full_name: '',
    email: '',
    bitget_api_key: '',
    bitget_api_secret: '',
    bitget_passphrase: ''
  });
  const [errors, setErrors] = useState({});
  const [message, setMessage] = useState('');
  const [apiConfigured, setApiConfigured] = useState(false);

  useEffect(() => {
    if (open) {
      loadUserProfile();
    }
  }, [open]);

  const loadUserProfile = async () => {
    try {
      setLoading(true);
      const response = await authService.getProfile();
      if (response.user) {
        const isConfigured = response.user.has_api_configured;
        setFormData({
          full_name: response.user.full_name || '',
          email: response.user.email || '',
          bitget_api_key: response.user.bitget_api_key || '',
          bitget_api_secret: isConfigured ? '••••••••••••••••' : '',
          bitget_passphrase: isConfigured ? '••••••••••••••••' : ''
        });
        setErrors({});
        setMessage('');
        setApiConfigured(isConfigured);
      } else {
        setMessage({ type: 'error', text: 'Erro ao carregar dados do perfil' });
      }
    } catch (error) {
      console.error('Erro ao carregar perfil:', error);
      setMessage({ type: 'error', text: error.message || 'Erro ao carregar dados do perfil' });
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (field) => (event) => {
    setFormData(prev => ({
      ...prev,
      [field]: event.target.value
    }));

    // Limpar erro do campo quando o usuário começar a digitar
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: ''
      }));
    }
  };

  // Auto-save das credenciais da API quando o usuário sair do campo
  const handleApiFieldBlur = async (field) => {
    const isApiField = ['bitget_api_key', 'bitget_api_secret', 'bitget_passphrase'].includes(field);
    if (!isApiField) return;

    // Verificar se todos os campos da API estão preenchidos
    const { bitget_api_key, bitget_api_secret, bitget_passphrase } = formData;
    if (bitget_api_key.trim() && bitget_api_secret.trim() && bitget_passphrase.trim() && 
        bitget_api_secret !== '••••••••••••••••' && bitget_passphrase !== '••••••••••••••••') {

      console.log('🔄 Auto-salvando credenciais da API...');
      try {
        await authService.updateProfile({
          bitget_api_key: bitget_api_key.trim(),
          bitget_api_secret: bitget_api_secret.trim(),
          bitget_passphrase: bitget_passphrase.trim()
        });

        toast.success('Credenciais da API salvas automaticamente!', {
          autoClose: 2000,
          position: 'bottom-right'
        });

        setApiConfigured(true);
      } catch (error) {
        console.error('Erro no auto-save:', error);
        toast.error('Erro ao salvar credenciais automaticamente', {
          autoClose: 3000,
          position: 'bottom-right'
        });
      }
    }
  };

  const validateForm = () => {
    const newErrors = {};

    if (!formData.full_name.trim()) {
      newErrors.full_name = 'Nome completo é obrigatório';
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email é obrigatório';
    } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
      newErrors.email = 'Email inválido';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSave = async () => {
    if (!validateForm()) {
      return;
    }

    try {
      setLoading(true);

      const updateData = {
        full_name: formData.full_name,
        email: formData.email
      };

      // Adicionar dados da API apenas se foram preenchidos
      if (formData.bitget_api_key.trim()) {
        updateData.bitget_api_key = formData.bitget_api_key;
      }
      // Apenas envia a secret key se ela foi alterada
      if (formData.bitget_api_secret.trim() && formData.bitget_api_secret !== '••••••••••••••••') {
        updateData.bitget_api_secret = formData.bitget_api_secret;
      }
      // Apenas envia a passphrase se ela foi alterada
      if (formData.bitget_passphrase.trim() && formData.bitget_passphrase !== '••••••••••••••••') {
        updateData.bitget_passphrase = formData.bitget_passphrase;
      }

      const response = await authService.updateProfile(updateData);

      if (onUserUpdate && response.user) {
        onUserUpdate(response.user);
      }

      toast.success('Perfil atualizado com sucesso!');
      onClose();
    } catch (error) {
      console.error('Erro ao atualizar perfil:', error);
      toast.error(error.message || 'Erro ao atualizar perfil');
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    if (!loading) {
      onClose();
    }
  };

  const isApiConfigured = formData.bitget_api_key && formData.bitget_api_secret && formData.bitget_passphrase;

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      maxWidth="md"
      fullWidth
      PaperProps={{
        sx: { 
          borderRadius: 2,
          maxHeight: '90vh',
          height: 'auto'
        }
      }}
    >
      <DialogTitle sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', pb: 1 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <Person color="primary" />
          <Typography variant="h6">Perfil do Usuário</Typography>
        </Box>
        <IconButton onClick={handleClose} disabled={loading}>
          <Close />
        </IconButton>
      </DialogTitle>

      <DialogContent 
        dividers
        sx={{
          maxHeight: '70vh',
          overflowY: 'auto',
          overflowX: 'hidden',
          '&::-webkit-scrollbar': {
            width: '8px'
          },
          '&::-webkit-scrollbar-track': {
            background: '#f1f1f1',
            borderRadius: '4px'
          },
          '&::-webkit-scrollbar-thumb': {
            background: '#c1c1c1',
            borderRadius: '4px'
          },
          '&::-webkit-scrollbar-thumb:hover': {
            background: '#a8a8a8'
          }
        }}
      >
        <Box sx={{ py: 1 }}>
          {/* Informações Pessoais */}
          <Card sx={{ mb: 3 }}>
            <CardContent>
              <Typography variant="h6" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <Person color="primary" />
                Informações Pessoais
              </Typography>

              <Grid container spacing={2}>
                <Grid item xs={12} sm={6}>
                  <TextField
                    fullWidth
                    label="Nome Completo"
                    value={formData.full_name}
                    onChange={handleInputChange('full_name')}
                    error={!!errors.full_name}
                    helperText={errors.full_name}
                    disabled={loading}
                  />
                </Grid>
                <Grid item xs={12} sm={6}>
                  <TextField
                    fullWidth
                    label="Email"
                    type="email"
                    value={formData.email}
                    onChange={handleInputChange('email')}
                    error={!!errors.email}
                    helperText={errors.email}
                    disabled={loading}
                  />
                </Grid>
              </Grid>
            </CardContent>
          </Card>

          {/* Configurações da API Bitget */}
          <Card>
            <CardContent>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <Api color="primary" />
                  API Bitget
                </Typography>
                {isApiConfigured && (
                  <Chip
                    icon={<Check />}
                    label="Configurada"
                    color="success"
                    size="small"
                  />
                )}
              </Box>

              <Alert severity="info" sx={{ mb: 2 }}>
                Configure suas credenciais da API Bitget para sincronizar automaticamente suas operações e saldo.
              </Alert>

              <Grid container spacing={2}>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="API Key"
                    value={formData.bitget_api_key}
                    onChange={handleInputChange('bitget_api_key')}
                    onBlur={() => handleApiFieldBlur('bitget_api_key')}
                    type={showApiKey ? 'text' : 'password'}
                    disabled={loading}
                    helperText="Salvo automaticamente quando todos os campos estão preenchidos"
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <IconButton
                            onClick={() => setShowApiKey(!showApiKey)}
                            edge="end"
                          >
                            {showApiKey ? <VisibilityOff /> : <Visibility />}
                          </IconButton>
                        </InputAdornment>
                      )
                    }}
                  />
                </Grid>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Secret Key"
                    value={formData.bitget_api_secret}
                    onChange={handleInputChange('bitget_api_secret')}
                    onBlur={() => handleApiFieldBlur('bitget_api_secret')}
                    type={showSecretKey ? 'text' : 'password'}
                    disabled={loading}
                    helperText="Salvo automaticamente quando todos os campos estão preenchidos"
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <IconButton
                            onClick={() => setShowSecretKey(!showSecretKey)}
                            edge="end"
                          >
                            {showSecretKey ? <VisibilityOff /> : <Visibility />}
                          </IconButton>
                        </InputAdornment>
                      )
                    }}
                  />
                </Grid>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Passphrase"
                    value={formData.bitget_passphrase}
                    onChange={handleInputChange('bitget_passphrase')}
                    onBlur={() => handleApiFieldBlur('bitget_passphrase')}
                    type={showPassphrase ? 'text' : 'password'}
                    disabled={loading}
                    helperText="Salvo automaticamente quando todos os campos estão preenchidos"
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <IconButton
                            onClick={() => setShowPassphrase(!showPassphrase)}
                            edge="end"
                          >
                            {showPassphrase ? <VisibilityOff /> : <Visibility />}
                          </IconButton>
                        </InputAdornment>
                      )
                    }}
                  />
                </Grid>
              </Grid>
            </CardContent>
          </Card>
        </Box>
      </DialogContent>

      <DialogActions sx={{ p: 2, gap: 1 }}>
        <Button
          onClick={handleClose}
          disabled={loading}
          variant="outlined"
        >
          Cancelar
        </Button>
        <Button
          onClick={handleSave}
          disabled={loading}
          variant="contained"
          startIcon={loading ? <CircularProgress size={20} /> : <Save />}
        >
          {loading ? 'Salvando...' : 'Salvar'}
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default Profile;
